/**
 * Notification log model — tracks sent notification history.
 *
 * Each NotificationLogEntry captures the full lifecycle of a notification:
 * who it was sent to, which channel was used, what type it was,
 * when it was sent, and whether delivery succeeded or failed.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/** Delivery status of a notification. */
export type DeliveryStatus = 'sent' | 'failed';

/**
 * A persistent record of a sent notification.
 */
export interface NotificationLogEntry {
  /** Unique log entry ID. */
  id: string;
  /** The notification ID from the notification system. */
  notificationId: string;
  /** User ID of the recipient (when available). */
  userId?: string;
  /** Recipient identifier (email address, webhook URL, etc.). */
  recipient: string;
  /** Delivery channel used. */
  channel: NotificationChannel;
  /** Semantic notification type. */
  type: NotificationType;
  /** Subject / title of the notification. */
  subject: string;
  /** Whether delivery succeeded or failed. */
  status: DeliveryStatus;
  /** Error message if delivery failed. */
  error?: string;
  /** When the notification was created. */
  createdAt: Date;
  /** When delivery was attempted. */
  deliveredAt: Date;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationLogQuery {
  userId?: string;
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLogEntry data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLogEntry, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      userId: record['userId'] as string | undefined,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      createdAt: new Date(record['createdAt'] as string),
      deliveredAt: new Date(record['deliveredAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      userId: entity.userId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      createdAt: entity.createdAt.toISOString(),
      deliveredAt: entity.deliveredAt.toISOString(),
    };
  }

  findByUserId(userId: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.userId === userId);
  }

  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.status === status);
  }
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * This service is responsible for persisting notification delivery records
 * and providing query capabilities over the notification log.
 *
 * Integration: NotificationService calls logNotification() after each dispatch.
 * This service is injected into NotificationService via setHistoryService().
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { PaginationResult } from '../utils/pagination.js';
import { paginate } from '../utils/pagination.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter. Useful for testing. */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification that was dispatched.
   * Called by NotificationService after each send attempt.
   */
  logNotification(payload: NotificationPayload, result: NotificationResult, userId?: string): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: payload.id,
      userId,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      subject: payload.subject,
      status: result.success ? 'sent' : 'failed',
      error: result.error,
      createdAt: payload.createdAt,
      deliveredAt: result.deliveredAt,
    };

    this.repository.save(entry);
    this.logger.info(`Logged notification ${payload.id} (${entry.status}) for ${payload.recipient}`);
    return entry;
  }

  /**
   * Query notification history with filters.
   */
  query(filters: NotificationLogQuery): NotificationLogEntry[] {
    return this.repository.findAll((entry) => {
      if (filters.userId !== undefined && entry.userId !== filters.userId) return false;
      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) return false;
      if (filters.channel !== undefined && entry.channel !== filters.channel) return false;
      if (filters.type !== undefined && entry.type !== filters.type) return false;
      if (filters.status !== undefined && entry.status !== filters.status) return false;
      if (filters.startDate !== undefined && entry.createdAt < filters.startDate) return false;
      if (filters.endDate !== undefined && entry.createdAt > filters.endDate) return false;
      return true;
    });
  }

  /**
   * Query with pagination support.
   */
  queryPaginated(filters: NotificationLogQuery, page: number = 1, pageSize: number = 20): PaginationResult<NotificationLogEntry> {
    const results = this.query(filters);
    return paginate(results, page, pageSize);
  }

  /**
   * Get all log entries for a specific user.
   */
  getByUserId(userId: string): NotificationLogEntry[] {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries of a specific notification type.
   */
  getByType(type: NotificationLogQuery['type']!): NotificationLogEntry[] {
    return this.repository.findByType(type!);
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.query({ startDate, endDate });
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLogEntry | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }

  /**
   * Get count of failed notifications.
   */
  getFailedCount(): number {
    return this.repository.findByStatus('failed').length;
  }
}

