import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a successful notification', () => {
      const payload = {
        id: 'notif-0001',
        type: 'order_confirmation' as const,
        channel: 'email' as const,
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        createdAt: new Date('2026-01-15T10:00:00Z'),
      };
      const result = {
        success: true,
        channel: 'email' as const,
        deliveredAt: new Date('2026-01-15T10:00:01Z'),
      };

      const entry = historyService.logNotification(payload, result, 'user-1');

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.userId).toBe('user-1');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.subject).toBe('Order Confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.error).toBeUndefined();
    });

    it('should log a failed notification', () => {
      const payload = {
        id: 'notif-0002',
        type: 'welcome' as const,
        channel: 'email' as const,
        recipient: 'bad-email',
        subject: 'Welcome',
        body: 'Welcome!',
        createdAt: new Date('2026-01-15T10:00:00Z'),
      };
      const result = {
        success: false,
        channel: 'email' as const,
        error: 'Invalid recipient',
        deliveredAt: new Date('2026-01-15T10:00:01Z'),
      };

      const entry = historyService.logNotification(payload, result);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Invalid recipient');
      expect(entry.userId).toBeUndefined();
    });

    it('should generate sequential log IDs', () => {
      const payload = {
        id: 'notif-0001',
        type: 'welcome' as const,
        channel: 'email' as const,
        recipient: 'a@b.com',
        subject: 'S',
        body: 'B',
        createdAt: new Date(),
      };
      const result = { success: true, channel: 'email' as const, deliveredAt: new Date() };

      const entry1 = historyService.logNotification(payload, result);
      const entry2 = historyService.logNotification({ ...payload, id: 'notif-0002' }, result);

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });
  });

  describe('query', () => {
    function seedEntries() {
      const base = {
        channel: 'email' as const,
        subject: 'Test',
        body: 'Test body',
      };
      const result = { success: true, channel: 'email' as const, deliveredAt: new Date('2026-01-15T12:00:00Z') };
      const failResult = { success: false, channel: 'email' as const, error: 'Failed', deliveredAt: new Date('2026-01-15T12:00:00Z') };

      historyService.logNotification(
        { ...base, id: 'n1', type: 'order_confirmation', recipient: 'alice@example.com', createdAt: new Date('2026-01-10T10:00:00Z') },
        result,
        'user-1',
      );
      historyService.logNotification(
        { ...base, id: 'n2', type: 'welcome', recipient: 'bob@example.com', createdAt: new Date('2026-01-12T10:00:00Z') },
        result,
        'user-2',
      );
      historyService.logNotification(
        { ...base, id: 'n3', type: 'order_status_update', recipient: 'alice@example.com', createdAt: new Date('2026-01-14T10:00:00Z') },
        failResult,
        'user-1',
      );
      historyService.logNotification(
        { ...base, id: 'n4', type: 'account_updated', recipient: 'charlie@example.com', channel: 'webhook', createdAt: new Date('2026-01-16T10:00:00Z') },
        { ...result, channel: 'webhook' },
        'user-3',
      );
    }

    it('should return all entries with empty filter', () => {
      seedEntries();
      const results = historyService.query({});
      expect(results).toHaveLength(4);
    });

    it('should filter by userId', () => {
      seedEntries();
      const results = historyService.query({ userId: 'user-1' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.userId === 'user-1')).toBe(true);
    });

    it('should filter by recipient', () => {
      seedEntries();
      const results = historyService.query({ recipient: 'bob@example.com' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by type', () => {
      seedEntries();
      const results = historyService.query({ type: 'order_confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should filter by channel', () => {
      seedEntries();
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      seedEntries();
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      seedEntries();
      const results = historyService.query({
        startDate: new Date('2026-01-11T00:00:00Z'),
        endDate: new Date('2026-01-15T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      seedEntries();
      const results = historyService.query({ userId: 'user-1', status: 'sent' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });
  });

  describe('queryPaginated', () => {
    it('should paginate results', () => {
      const base = { channel: 'email' as const, subject: 'S', body: 'B' };
      const result = { success: true, channel: 'email' as const, deliveredAt: new Date() };

      for (let i = 1; i <= 5; i++) {
        historyService.logNotification(
          { ...base, id: `n${i}`, type: 'welcome', recipient: `user${i}@test.com`, createdAt: new Date() },
          result,
          `user-${i}`,
        );
      }

      const page1 = historyService.queryPaginated({}, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);

      const page3 = historyService.queryPaginated({}, 3, 2);
      expect(page3.items).toHaveLength(1);
      expect(page3.hasNext).toBe(false);
      expect(page3.hasPrevious).toBe(true);
    });
  });

  describe('convenience query methods', () => {
    beforeEach(() => {
      const base = { channel: 'email' as const, subject: 'S', body: 'B' };
      const result = { success: true, channel: 'email' as const, deliveredAt: new Date() };

      historyService.logNotification(
        { ...base, id: 'n1', type: 'order_confirmation', recipient: 'alice@example.com', createdAt: new Date() },
        result,
        'user-1',
      );
      historyService.logNotification(
        { ...base, id: 'n2', type: 'welcome', recipient: 'bob@example.com', createdAt: new Date() },
        { success: false, channel: 'email', error: 'Bad', deliveredAt: new Date() },
        'user-2',
      );
    });

    it('getByUserId should return entries for a user', () => {
      expect(historyService.getByUserId('user-1')).toHaveLength(1);
      expect(historyService.getByUserId('user-99')).toHaveLength(0);
    });

    it('getByRecipient should return entries for a recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
    });

    it('getByType should return entries of a given type', () => {
      expect(historyService.getByType('welcome')).toHaveLength(1);
    });

    it('getById should return a single entry', () => {
      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('n1');
    });

    it('getById should return undefined for unknown ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('getCount should return total log count', () => {
      expect(historyService.getCount()).toBe(2);
    });

    it('getFailedCount should return count of failed notifications', () => {
      expect(historyService.getFailedCount()).toBe(1);
    });
  });

  describe('getByDateRange', () => {
    it('should return entries within the date range', () => {
      const result = { success: true, channel: 'email' as const, deliveredAt: new Date() };
      const base = { channel: 'email' as const, subject: 'S', body: 'B', type: 'welcome' as const };

      historyService.logNotification(
        { ...base, id: 'n1', recipient: 'a@b.com', createdAt: new Date('2026-01-01T00:00:00Z') },
        result,
      );
      historyService.logNotification(
        { ...base, id: 'n2', recipient: 'c@d.com', createdAt: new Date('2026-06-15T00:00:00Z') },
        result,
      );
      historyService.logNotification(
        { ...base, id: 'n3', recipient: 'e@f.com', createdAt: new Date('2026-12-31T00:00:00Z') },
        result,
      );

      const results = historyService.getByDateRange(
        new Date('2026-03-01T00:00:00Z'),
        new Date('2026-09-01T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('n2');
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications dispatched via NotificationService', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const entries = historyService.getByUserId('user-1');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.type).toBe('order_confirmation');
      expect(entries[0]?.status).toBe('sent');
      expect(entries[0]?.channel).toBe('email');
    });

    it('should log failed notifications when no adapter registered', async () => {
      const noAdapterBus = new EventBus();
      const noAdapterService = new NotificationService(noAdapterBus);
      noAdapterService.setHistoryService(historyService);

      await noAdapterBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const entries = historyService.query({ status: 'failed' });
      expect(entries).toHaveLength(1);
      expect(entries[0]?.error).toContain('No adapter registered');
    });

    it('should log multiple notifications from different events', async () => {
      const orderEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(orderEvent);
      await eventBus.emit(statusEvent);

      expect(historyService.getCount()).toBe(2);
      const byType = historyService.getByType('order_confirmation');
      expect(byType).toHaveLength(1);
    });

    it('should not log when history service is not set', async () => {
      const plainBus = new EventBus();
      const plainService = new NotificationService(plainBus);
      plainService.registerAdapter(new EmailAdapter());

      await plainBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      // History service was not set on plainService, so our historyService should have no entries
      expect(historyService.getCount()).toBe(0);
      // But the notification was still sent
      expect(plainService.getNotificationCount()).toBe(1);
    });
  });
});

