+/**
+ * Notification log model — tracks sent notification history.
+ *
+ * Each NotificationLogEntry captures the full lifecycle of a notification:
+ * who it was sent to, which channel was used, what type it was,
+ * when it was sent, and whether delivery succeeded or failed.
+ */
+
+import type { NotificationType, NotificationChannel } from './notification.js';
+
+/** Delivery status of a notification. */
+export type DeliveryStatus = 'sent' | 'failed';
+
+/**
+ * A persistent record of a sent notification.
+ */
+export interface NotificationLogEntry {
+  /** Unique log entry ID. */
+  id: string;
+  /** The notification ID from the notification system. */
+  notificationId: string;
+  /** User ID of the recipient (when available). */
+  userId?: string;
+  /** Recipient identifier (email address, webhook URL, etc.). */
+  recipient: string;
+  /** Delivery channel used. */
+  channel: NotificationChannel;
+  /** Semantic notification type. */
+  type: NotificationType;
+  /** Subject / title of the notification. */
+  subject: string;
+  /** Whether delivery succeeded or failed. */
+  status: DeliveryStatus;
+  /** Error message if delivery failed. */
+  error?: string;
+  /** When the notification was created. */
+  createdAt: Date;
+  /** When delivery was attempted. */
+  deliveredAt: Date;
+}
+
+/**
+ * Query filters for searching notification history.
+ */
+export interface NotificationLogQuery {
+  userId?: string;
+  recipient?: string;
+  channel?: NotificationChannel;
+  type?: NotificationType;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

