+/**
+ * Notification history service — logs and queries sent notification history.
+ *
+ * This service is responsible for persisting notification delivery records
+ * and providing query capabilities over the notification log.
+ *
+ * Integration: NotificationService calls logNotification() after each dispatch.
+ * This service is injected into NotificationService via setHistoryService().
+ */
+
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type { NotificationLogEntry, NotificationLogQuery } from '../models/notification-log.js';
+import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
+import type { PaginationResult } from '../utils/pagination.js';
+import { paginate } from '../utils/pagination.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+/** Reset the log ID counter. Useful for testing. */
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification that was dispatched.
+   * Called by NotificationService after each send attempt.
+   */
+  logNotification(payload: NotificationPayload, result: NotificationResult, userId?: string): NotificationLogEntry {
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: payload.id,
+      userId,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      subject: payload.subject,
+      status: result.success ? 'sent' : 'failed',
+      error: result.error,
+      createdAt: payload.createdAt,
+      deliveredAt: result.deliveredAt,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(`Logged notification ${payload.id} (${entry.status}) for ${payload.recipient}`);
+    return entry;
+  }
+
+  /**
+   * Query notification history with filters.
+   */
+  query(filters: NotificationLogQuery): NotificationLogEntry[] {
+    return this.repository.findAll((entry) => {
+      if (filters.userId !== undefined && entry.userId !== filters.userId) return false;
+      if (filters.recipient !== undefined && entry.recipient !== filters.recipient) return false;
+      if (filters.channel !== undefined && entry.channel !== filters.channel) return false;
+      if (filters.type !== undefined && entry.type !== filters.type) return false;
+      if (filters.status !== undefined && entry.status !== filters.status) return false;
+      if (filters.startDate !== undefined && entry.createdAt < filters.startDate) return false;
+      if (filters.endDate !== undefined && entry.createdAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Query with pagination support.
+   */
+  queryPaginated(filters: NotificationLogQuery, page: number = 1, pageSize: number = 20): PaginationResult<NotificationLogEntry> {
+    const results = this.query(filters);
+    return paginate(results, page, pageSize);
+  }
+
+  /**
+   * Get all log entries for a specific user.
+   */
+  getByUserId(userId: string): NotificationLogEntry[] {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get all log entries for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all log entries of a specific notification type.
+   */
+  getByType(type: NotificationType): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all log entries within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
+    return this.query({ startDate, endDate });
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLogEntry | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get the total count of logged notifications.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+
+  /**
+   * Get count of failed notifications.
+   */
+  getFailedCount(): number {
+    return this.repository.findByStatus('failed').length;
+  }
+}

